B.Sv=new A.eo("Deckelisolation","Styrodur 30-50 mm unter dem Blechdeckel.\nVerhindert Kondenswasser im Winter.\nSch\xfctzt vor extremen Temperaturschwankungen.",B.uB,!1,null)
B.Sw=new A.eo("Vorteile","\u2022 Premium-Honig (Alpenbl\xfcten, Alpenrosen)\n\u2022 Weniger Pestizidbelastung\n\u2022 Geringerer Krankheitsdruck\n\u2022 Hohe Preise erzielbar (CHF 18-25/500g)",B.o0,!0,null)
